/// <summary>
///
/// </summary>
/// <param name="args"></param>
[PreHandlerFor(formStr(PdsResetVendorBatchDetails), formMethodStr(PdsResetVendorBatchDetails, init))]
public static void PdsResetVendorBatchDetails_Pre_init(XppPrePostArgs args)
{
    FormRun fr = args.getThis();
    Common common = fr.args().record();

    switch (common.TableId)
    {
        case tableNum(InventValueReportTmpLine):
            InventValueReportTmpLine InventValueReportTmpLine = common;
            InventDim inventDim = Global::getJoinChildFormDataSource(FormDataUtil::getFormDataSource(InventValueReportTmpLine), tableNum(InventDim)).cursor() as InventDim;
            InventBatch inventBatch = InventBatch::find(inventDim.inventBatchId, InventValueReportTmpLine.ResourceId);
            fr.args().record(inventBatch);

            break;
    }
}
